export enum Role {
  USER = 'user',
  MODEL = 'model'
}

export enum MessageType {
  TEXT = 'text',
  IMAGE = 'image',
  AUDIO = 'audio'
}

export interface Attachment {
  mimeType: string;
  data: string; // Base64 string
  type: MessageType;
}

export interface Message {
  id: string;
  role: Role;
  content: string;
  attachments?: Attachment[];
  timestamp: number;
}

export interface Theme {
  id: string;
  name: string;
  primary: string;
  secondary: string;
  background: string;
  text: string;
  bubbleUser: string;
  bubbleModel: string;
  isDark: boolean;
}

import { GoogleGenAI } from "@google/genai";
import { Attachment, Message, Role } from "../types";
import { GEMINI_MODEL } from "../constants";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const solveMathProblem = async (
  currentMessage: string,
  attachments: Attachment[],
  history: Message[]
): Promise<string> => {
  try {
    // Construct the history for context
    // We limit history to last 10 messages to keep context relevant but not huge
    const relevantHistory = history.slice(-10).map(msg => ({
      role: msg.role === Role.USER ? 'user' : 'model',
      parts: [{ text: msg.content }]
    }));

    // Prepare current content parts
    const parts: any[] = [];

    // Add text if exists
    if (currentMessage) {
      parts.push({ text: currentMessage });
    }

    // Add attachments (images/audio)
    attachments.forEach(att => {
      parts.push({
        inlineData: {
          mimeType: att.mimeType,
          data: att.data
        }
      });
    });

    // Add a system instruction wrapper to the prompt if it's the start of a new topic
    // or implicitly via the model config
    const systemInstruction = `You are an expert Math and Geometry tutor. 
    1. Solve problems step-by-step. 
    2. If an image is provided, analyze the geometry, graphs, or handwritten equations carefully. 
    3. If audio is provided, listen to the math problem and transcribe it before solving.
    4. Use LaTeX formatting for math equations (wrap in single $ for inline, double $$ for block).
    5. Be encouraging and clear.`;

    const response = await ai.models.generateContent({
      model: GEMINI_MODEL,
      contents: [
        ...relevantHistory,
        { role: 'user', parts: parts }
      ],
      config: {
        systemInstruction: systemInstruction,
        thinkingConfig: { thinkingBudget: 2048 }, // Enable thinking for complex math
        temperature: 0.2, // Low temperature for precision in math
      }
    });

    return response.text || "I couldn't generate a solution. Please try again.";
  } catch (error: any) {
    console.error("Gemini API Error:", error);
    return `Error: ${error.message || "Something went wrong while solving the problem."}`;
  }
};

import React from 'react';
import ReactMarkdown from 'react-markdown';
import remarkMath from 'remark-math';
import rehypeKatex from 'rehype-katex';

interface MathRendererProps {
  content: string;
  isDark: boolean;
}

const MathRenderer: React.FC<MathRendererProps> = ({ content, isDark }) => {
  return (
    <div className={`markdown-body ${isDark ? 'text-slate-100' : 'text-slate-800'} text-sm md:text-base leading-relaxed overflow-x-auto`}>
      <ReactMarkdown
        remarkPlugins={[remarkMath]}
        rehypePlugins={[rehypeKatex]}
        components={{
          p: ({ children }) => <p className="mb-2 last:mb-0">{children}</p>,
          h1: ({ children }) => <h1 className="text-xl font-bold mb-2 mt-4">{children}</h1>,
          h2: ({ children }) => <h2 className="text-lg font-bold mb-2 mt-3">{children}</h2>,
          h3: ({ children }) => <h3 className="text-md font-bold mb-1 mt-2">{children}</h3>,
          ul: ({ children }) => <ul className="list-disc list-inside mb-2 ml-2">{children}</ul>,
          ol: ({ children }) => <ol className="list-decimal list-inside mb-2 ml-2">{children}</ol>,
          li: ({ children }) => <li className="mb-1">{children}</li>,
          code: ({ children }) => <code className={`${isDark ? 'bg-slate-700' : 'bg-slate-100'} px-1 py-0.5 rounded text-sm font-mono`}>{children}</code>,
