export default MathRenderer;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Attachment, MessageType } from '../types';

interface InputAreaProps {
  onSend: (text: string, attachments: Attachment[]) => void;
  isLoading: boolean;
  themePrimary: string;
  isDark: boolean;
}

const InputArea: React.FC<InputAreaProps> = ({ onSend, isLoading, themePrimary, isDark }) => {
  const [inputText, setInputText] = useState('');
  const [isRecording, setIsRecording] = useState(false);
  const [recordingDuration, setRecordingDuration] = useState(0);
  const [attachment, setAttachment] = useState<Attachment | null>(null);

  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const timerRef = useRef<number | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Handle auto-resize of textarea
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      textareaRef.current.style.height = textareaRef.current.scrollHeight + 'px';
    }
  }, [inputText]);

  const handleStartRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) {
          audioChunksRef.current.push(event.data);
        }
      };

      mediaRecorder.start();
      setIsRecording(true);
      setRecordingDuration(0);

      timerRef.current = window.setInterval(() => {
        setRecordingDuration(prev => prev + 1);
      }, 1000);

    } catch (err) {
      console.error("Error accessing microphone:", err);
      alert("Could not access microphone. Please check permissions.");
    }
  };

  const handleStopRecording = useCallback((shouldSend: boolean) => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      mediaRecorderRef.current.onstop = async () => {
        if (shouldSend && audioChunksRef.current.length > 0) {
          const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' }); // Use webm for broad compatibility
          const reader = new FileReader();
          reader.readAsDataURL(audioBlob);
          reader.onloadend = () => {
            const base64String = (reader.result as string).split(',')[1];
            // Send immediately as audio message
            onSend("", [{
              mimeType: 'audio/webm',
              data: base64String,
              type: MessageType.AUDIO
            }]);
          };
        }

        // Cleanup
        if (mediaRecorderRef.current?.stream) {
          mediaRecorderRef.current.stream.getTracks().forEach(track => track.stop());
        }
        setIsRecording(false);
        if (timerRef.current) {
          clearInterval(timerRef.current);
          timerRef.current = null;
        }
      };
    }
  }, [isRecording, onSend]);

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        setAttachment({
          mimeType: file.type,
          data: base64String,
          type: MessageType.IMAGE
        });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSendText = () => {
    if (!inputText.trim() && !attachment) return;

    const attachments = attachment ? [attachment] : [];
    onSend(inputText, attachments);
    setInputText('');
    setAttachment(null);
    if (textareaRef.current) textareaRef.current.style.height = 'auto';
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendText();
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs < 10 ? '0' : ''}${secs}`;
  };

  return (
    <div className={`p-4 ${isDark ? 'bg-slate-900 border-t border-slate-800' : 'bg-white border-t border-slate-100'}`}>
      {/* Attachment Preview */}
      {attachment && (
        <div className="relative inline-block mb-2">
          <img 
            src={`data:${attachment.mimeType};base64,${attachment.data}`} 
            alt="Preview" 
            className="h-20 w-20 object-cover rounded-lg border border-slate-300"
          />
          <button 
            onClick={() => setAttachment(null)}
            className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-1 w-6 h-6 flex items-center justify-center text-xs shadow-md hover:bg-red-600 transition-colors"
          >
            <i className="fas fa-times"></i>
          </button>
        </div>
      )}

      <div className="flex items-end gap-2 max-w-4xl mx-auto">

        {/* Attachment Button */}
        <button 
          onClick={() => fileInputRef.current?.click()}
          className={`p-3 rounded-full transition-all ${isDark ? 'text-slate-400 hover:text-slate-200 hover:bg-slate-800' : 'text-slate-500 hover:text-slate-700 hover:bg-slate-100'}`}
          title="Upload Image"
        >
          <i className="fas fa-plus"></i>
        </button>
        <input 
          type="file" 
          ref={fileInputRef} 
          className="hidden" 
          accept="image/*"
          onChange={handleFileSelect}
        />

        {/* Input Field or Recording State */}
        <div className={`flex-1 flex items-center rounded-2xl px-4 py-2 min-h-[48px] ${isDark ? 'bg-slate-800' : 'bg-slate-100'}`}>
          {isRecording ? (
            <div className="flex items-center w-full justify-between animate-pulse text-red-500">
              <div className="flex items-center gap-2">
                <i className="fas fa-microphone"></i>
                <span className="font-semibold">Recording... {formatTime(recordingDuration)}</span>
              </div>
              <span className="text-xs uppercase tracking-wider font-bold">Release to Send</span>
            </div>
          ) : (
            <textarea
              ref={textareaRef}
              value={inputText}
              onChange={(e) => setInputText(e.target.value)}
              onKeyDown={handleKeyDown}
              placeholder="Ask a math problem..."
              className={`w-full bg-transparent border-none focus:ring-0 resize-none max-h-32 py-2 ${isDark ? 'text-white placeholder-slate-400' : 'text-slate-900 placeholder-slate-500'}`}
              rows={1}
            />
          )}
        </div>

        {/* Dynamic Action Button (Send or Mic) */}
        {inputText.trim() || attachment ? (
           <button 
             onClick={handleSendText}
             disabled={isLoading}
             className={`p-3 rounded-full w-12 h-12 flex items-center justify-center transition-all shadow-md transform hover:scale-105 active:scale-95 ${themePrimary} text-white disabled:opacity-50 disabled:cursor-not-allowed`}
           >
             {isLoading ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-paper-plane"></i>}
           </button>
        ) : (
          <button 
            onMouseDown={handleStartRecording}
            onMouseUp={() => handleStopRecording(true)}
            onMouseLeave={() => isRecording && handleStopRecording(false)} // Cancel if dragged out
            onTouchStart={(e) => { e.preventDefault(); handleStartRecording(); }}
            onTouchEnd={(e) => { e.preventDefault(); handleStopRecording(true); }}
            disabled={isLoading}
            className={`p-3 rounded-full w-12 h-12 flex items-center justify-center transition-all shadow-md transform ${isRecording ? 'bg-red-500 scale-110 recording-pulse' : themePrimary} text-white disabled:opacity-50 disabled:cursor-not-allowed`}
          >
             <i className={`fas fa-microphone ${isRecording ? 'scale-110' : ''}`}></i>
          </button>
        )}
      </div>
      <div className="text-center mt-2">
         {isRecording && <p className={`text-xs ${isDark ? 'text-slate-400' : 'text-slate-500'}`}>Slide away to cancel</p>}
      </div>
    </div>
  );
};

export default InputArea;

import React, { useState, useEffect, useRef } from 'react';
import { THEMES } from './constants';
import { Theme, Message, Role, Attachment, MessageType } from './types';
import InputArea from './components/InputArea';
import MathRenderer from './components/MathRenderer';
import { solveMathProblem } from './services/geminiService';
import { v4 as uuidv4 } from 'uuid';

const App: React.FC = () => {
  const [currentTheme, setCurrentTheme] = useState<Theme>(THEMES[0]);
  const [messages, setMessages] = useState<Message[]>([
    {
      id: 'welcome',
      role: Role.MODEL,
      content: "Hello! I'm your AI Math Tutor. I can help you with Algebra, Geometry, Calculus, and more. You can type your problem, upload an image of it, or hold the mic button to dictate it.",
      timestamp: Date.now()
    }
  ]);
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSendMessage = async (text: string, attachments: Attachment[]) => {
    const userMsgId = uuidv4();
    const newUserMessage: Message = {
      id: userMsgId,
      role: Role.USER,
      content: text,
      attachments: attachments,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, newUserMessage]);
    setIsLoading(true);

    // If audio attachment, add a "Transcribing & Solving..." placeholder logic visually handled by loading state
    // But logically, we send the audio to Gemini directly.

    const solutionText = await solveMathProblem(text, attachments, messages);

    const modelMsgId = uuidv4();
    const newModelMessage: Message = {
      id: modelMsgId,
      role: Role.MODEL,
      content: solutionText,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, newModelMessage]);
    setIsLoading(false);
  };

  return (
    <div className={`h-screen w-full flex flex-col ${currentTheme.background} transition-colors duration-300`}>
      {/* Header */}
      <header className={`${currentTheme.secondary} p-4 shadow-md flex justify-between items-center z-10`}>
        <div className="flex items-center gap-3">
          <div className={`w-10 h-10 rounded-full ${currentTheme.primary} flex items-center justify-center text-white font-bold text-xl`}>
            <i className="fas fa-square-root-variable"></i>
          </div>
          <div>
            <h1 className={`font-bold text-lg ${currentTheme.text}`}>MathGenius</h1>
            <p className={`text-xs opacity-70 ${currentTheme.text}`}>AI Solver</p>
          </div>
        </div>

        {/* Theme Selector */}
        <div className="flex gap-2">
          {THEMES.map(theme => (
            <button
              key={theme.id}
              onClick={() => setCurrentTheme(theme)}
              className={`w-6 h-6 rounded-full border-2 ${currentTheme.id === theme.id ? 'border-white scale-110 shadow-lg' : 'border-transparent opacity-60'} ${theme.primary}`}
              title={theme.name}
            />
          ))}
        </div>
      </header>

      {/* Chat Area */}
      <main className="flex-1 overflow-y-auto p-4 md:p-6 scroll-smooth">
        <div className="max-w-4xl mx-auto space-y-6">
          {messages.map((msg) => {
            const isUser = msg.role === Role.USER;
            return (
              <div key={msg.id} className={`flex ${isUser ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] md:max-w-[75%] rounded-2xl px-5 py-3 shadow-sm ${isUser ? currentTheme.bubbleUser : currentTheme.bubbleModel}`}>

                  {/* Attachments rendering */}
                  {msg.attachments && msg.attachments.length > 0 && (
                    <div className="mb-3 flex flex-wrap gap-2">
                      {msg.attachments.map((att, idx) => {
                        if (att.type === MessageType.IMAGE) {
                          return (
                            <img 
                              key={idx} 
                              src={`data:${att.mimeType};base64,${att.data}`} 
                              alt="User upload" 
                              className="rounded-lg max-h-48 border border-white/20" 
                            />
                          );
                        } else if (att.type === MessageType.AUDIO) {
                          return (
                             <div key={idx} className="flex items-center gap-2 bg-black/10 p-2 rounded-lg">
                               <i className="fas fa-microphone-lines"></i>
                               <span className="text-xs">Audio Clip</span>
                             </div>
                          );
                        }
                        return null;
                      })}
                    </div>
                  )}

                  {/* Text Content */}
                  {msg.content && (
                    <div className={isUser ? '' : 'math-content'}>
                       {isUser ? (
                         <p className="whitespace-pre-wrap">{msg.content}</p>
                       ) : (
                         <MathRenderer content={msg.content} isDark={currentTheme.isDark && !isUser} />
                       )}
                    </div>
                  )}

                  <div className={`text-[10px] mt-1 text-right opacity-60`}>
                    {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </div>
                </div>
              </div>
            );
          })}

          {isLoading && (
            <div className="flex justify-start">
               <div className={`rounded-2xl px-5 py-3 ${currentTheme.bubbleModel} flex items-center gap-2`}>
                 <div className="flex space-x-1">
                   <div className={`w-2 h-2 rounded-full ${currentTheme.primary} animate-bounce`} style={{ animationDelay: '0s' }}></div>
                   <div className={`w-2 h-2 rounded-full ${currentTheme.primary} animate-bounce`} style={{ animationDelay: '0.2s' }}></div>
                   <div className={`w-2 h-2 rounded-full ${currentTheme.primary} animate-bounce`} style={{ animationDelay: '0.4s' }}></div>
                 </div>
                 <span className={`text-xs ${currentTheme.text} opacity-70`}>Thinking...</span>
               </div>
            </div>
          )}
          <div ref={messagesEndRef} />
        </div>
      </main>

      {/* Input Area */}
      <InputArea 
        onSend={handleSendMessage} 
        isLoading={isLoading} 
        themePrimary={currentTheme.primary}
        isDark={currentTheme.isDark}
      />
    </div>
  );
};

export default App;

