export enum Role {
  USER = 'user',
  MODEL = 'model'
}

export enum MessageType {
  TEXT = 'text',
  IMAGE = 'image',
  AUDIO = 'audio'
}

export type Language = 'en' | 'fr' | 'ar';

export interface Attachment {
  mimeType: string;
  data: string; // Base64 string
  type: MessageType;
}

export interface Message {
  id: string;
  role: Role;
  content: string;
  attachments?: Attachment[];
  timestamp: number;
}

export interface Theme {
