  bubbleModel: string;
}

export interface Translations {
  welcome: string;
  inputPlaceholder: string;
  recording: string;
  releaseToSend: string; // repurposed as "Stop"
  thinking: string;
  settings: string;
  language: string;
  theme: string;
  clearChat: string;
  uploadImage: string;
  send: string;
  appName: string;
  tagline: string;
  error429: string;
  madeBy: string;
}

import { GoogleGenAI } from "@google/genai";
import { Attachment, Message, Role, Language, Translations } from "../types";
import { GEMINI_MODEL, TRANSLATIONS } from "../constants";

export const solveMathProblem = async (
  currentMessage: string,
  attachments: Attachment[],
  history: Message[],
  language: Language
): Promise<string> => {
  const t = TRANSLATIONS[language];
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    // Construct the history for context
    const relevantHistory = history.slice(-10).map(msg => ({
      role: msg.role === Role.USER ? 'user' : 'model',
      parts: [{ text: msg.content }]
    }));

    // Prepare current content parts
    const parts: any[] = [];

    if (currentMessage) {
      parts.push({ text: currentMessage });
    }

    attachments.forEach(att => {
      parts.push({
        inlineData: {
          mimeType: att.mimeType,
          data: att.data
        }
      });
    });

    // Language specific instruction
    let langInstruction = "English";
    if (language === 'fr') langInstruction = "French";
    if (language === 'ar') langInstruction = "Arabic";

    const systemInstruction = `You are "Math Bro", an expert Math and Geometry tutor. 
    1. Respond strictly in ${langInstruction}.
    2. Solve problems step-by-step. 
    3. If an image is provided, analyze the geometry, graphs, or handwritten equations carefully. 
    4. Use LaTeX formatting for math equations (wrap in single $ for inline, double $$ for block).
    5. Be encouraging, clear, and concise.`;

    const response = await ai.models.generateContent({
      model: GEMINI_MODEL,
      contents: [
        ...relevantHistory,
        { role: 'user', parts: parts }
      ],
      config: {
        systemInstruction: systemInstruction,
        thinkingConfig: { thinkingBudget: 2048 },
        temperature: 0.2,
      }
    });

    return response.text || "Error: No response generated.";
  } catch (error: any) {
    console.error("Gemini API Error:", error);

    // Check for 429 specifically
    if (error.message?.includes('429') || error.status === 429) {
      return `⚠️ ${t.error429}`;
    }

    return `Error: ${error.message || "Something went wrong."}`;
  }
};

